const Q_IRK_2008=[{"id": "objective>IRK>2008>1", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The complete Glorious was Qur'an taken from Lawn al-mahfuz to the lowest of the heavens known as</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Bait al- Izzah</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Bait al- Maqdis</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Bait al-Haram</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Bait al-Hikmah</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The complete Glorious Qur'an was taken from Lawn al-mahfuz to the lowest of the heavens known as Bait al- Izzah. Lawn al-mahfuz, also known as the Preserved Tablet, is the divine record that contains all that has happened and will happen. Bait al- Izzah, also known as the House of Honor, is believed to be the location in the lowest heaven where the Qur'an was first brought down.</div>", "topic": "PRESERVATION OF THE GLORIOUS QUR’AN : THE ROLE PLAYED BY THECOMPANIONS OF THE PROPHET (SAW)"}, {"id": "objective>IRK>2008>2", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The most important ways of preserving the Glorious Qur'an by Sah'bah include</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">establishing schools in major cities and teaching the Glorious Qur'an</div>", "<div style=\"font-family:Cambria;font-size:17px;\">teaching the application of sunnah practically</div>", "<div style=\"font-family:Cambria;font-size:17px;\">explaining the conduct of the prophet according to the Glorious Qur'an</div>", "<div style=\"font-family:Cambria;font-size:17px;\">guiding the new converts in Islam ways of life</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The Sah'bah, the companions of the Prophet Muhammad, played a crucial role in preserving the Glorious Qur'an. One of the most important ways they did this was by establishing schools in major cities and teaching the Glorious Qur'an. This helped to ensure that the Qur'an was accurately transmitted to future generations.</div>", "topic": "PRESERVATION OF THE GLORIOUS QUR’AN : COMPLETE ARRANGEMENT"}, {"id": "objective>IRK>2008>3", "question": "<div style=\"font-family:Cambria;font-size:17px;\">What are the characteristics common to most Makkan Suwar?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">They are short and poetic</div>", "<div style=\"font-family:Cambria;font-size:17px;\">They are long and rhythmic</div>", "<div style=\"font-family:Cambria;font-size:17px;\">They are easy and rhythmic</div>", "<div style=\"font-family:Cambria;font-size:17px;\">They are stylistic and summative</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The Makkan Suwar, or Meccan chapters of the Qur'an, are generally characterized as being short and poetic. These chapters were revealed while the Prophet Muhammad was in Mecca, and they often deal with themes of faith, the afterlife, and the judgment of God.</div>", "topic": "PRESERVATION OF THE GLORIOUS QUR’AN : DIFFERENCES BETWEEN MAKKAH AND MADINAN SUWAR"}, {"id": "objective>IRK>2008>4", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The Glorious Qur'an is a guidance for</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">The pious</div>", "<div style=\"font-family:Cambria;font-size:17px;\">All mankind</div>", "<div style=\"font-family:Cambria;font-size:17px;\">The Arabs</div>", "<div style=\"font-family:Cambria;font-size:17px;\">The Quraish</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Qur'an 2:2 \"This is the Book about which there is no doubt, a guidance for those conscious of Allah.\"</div>", "topic": "IMPORTANCE OF THE GLORIOUS QUR’AN : AS SOURCE OF GUIDANCE IN SPIRITUAL, MORAL, ECONOMIC, POLITICAL AND SOCIO-CULTURAL MATTERS."}, {"id": "objective>IRK>2008>5", "question": "<div style=\"font-family:Cambria;font-size:17px;\">What will happen on the Day of Judgment according to Q.101:5?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Mountains will discharge fire</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Mountains will be like carded wool</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Fire of Jahannam will be seen</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Sun will be extremely hot</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Q.101:5 \"And the mountains will be like carded wool.\"</div>", "topic": "ARTICLE OF FAITH : THE LAST DAY: YAWM-AL-BA'TH"}, {"id": "objective>IRK>2008>6", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Every human being, according to Surah al-Asr is in a state of loss, except the</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Quraish tribe</div>", "<div style=\"font-family:Cambria;font-size:17px;\">the oppressed people</div>", "<div style=\"font-family:Cambria;font-size:17px;\">faithful and righteous</div>", "<div style=\"font-family:Cambria;font-size:17px;\">earlier generations</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Surah Al-Asr (103:1-3) in the Quran states that every human being is in a state of loss, except those who have faith, do righteous deeds, advise each other to truth and advise each other to patience. Therefore, the correct answer is 'faithful and righteous'.</div>", "topic": "IBADAT AND THEIR TYPES : GOOD DEEDS 26TH HADITH OF AN-NAWAWI"}, {"id": "objective>IRK>2008>7", "question": "<div style=\"font-family:Cambria;font-size:17px;\">\"So verily, with every difficulty, there is relief\" the best Arabic translation of the verse above is represented in</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\"><img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/></div>", "<div style=\"font-family:Cambria;font-size:17px;\"><img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/></div>", "<div style=\"font-family:Cambria;font-size:17px;\"><img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/></div>", "<div style=\"font-family:Cambria;font-size:17px;\"><img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/></div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Qur'an 94:5 (English): <br/> \"For indeed, with hardship [will be] ease.\"</div>", "topic": "STUDY OF THE ARABIC TEXT OF THE FOLLOWING SUWAR/AYATS WITH TAJWID : AL-INSHIRAH"}, {"id": "objective>IRK>2008>8", "question": "<div style=\"font-family:Cambria;font-size:17px;\"><img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/> The translation of the verse above is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">truly, man is to his lord ungrateful</div>", "<div style=\"font-family:Cambria;font-size:17px;\">\"verily, to thy Lord is the return (of all)\"</div>", "<div style=\"font-family:Cambria;font-size:17px;\">\"And verily the hereafter will be better for thee than present\"</div>", "<div style=\"font-family:Cambria;font-size:17px;\">\"truly, he succeeds that purifies</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Qur'an 96:8 (English): <br/> \"Indeed, to your Lord is the return.\"</div>", "topic": "STUDY OF THE ARABIC TEXT OF THE FOLLOWING SUWAR/AYATS WITH TAJWID : AL-ALAQ"}, {"id": "objective>IRK>2008>9", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The verse that can be recited for protection against evil machinations is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Q. 2:286</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Q. 2:285</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Q. 2:256</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Q. 2:255</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Quran 2:255, also known as Ayat al-Kursi, is often recited for protection against evil. It speaks about Allah's sovereignty, knowledge, and power. It is considered one of the most excellent verses of the Quran.</div>", "topic": "STUDY OF THE ARABIC TEXT OF THE FOLLOWING SUWAR/AYATS WITH TAJWID : AYATUL-KURSIY"}, {"id": "objective>IRK>2008>10", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The official compilation of Hadith was facilitated by</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Caliph Umar b. al-khattab</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Caliph Uthman b. Affan</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Caliph Mu'awiyah b. Abi Sufyan</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Caliph Umar b. Abdul-Aziz</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Compilation of Hadith was done during the reign of Umar bui Abdulzeez, an ummayad dynasty Caliph. He ordered the compilation of hadith because people at that time started to fabricate hadith to confuse the muslims. </div>", "topic": "HADITH : HISTORY OF HADITH LITERATURE -COLLECTION OF HADITH FROM THE TIME OF THE PROPHET-SAW TO THE PERIOD OF THE SIX AUTHENTIC COLLECTORS OF HADITH"}, {"id": "objective>IRK>2008>11", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The science of Asma al-rijal is introduced in order to</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Authenticate the chains of Hadith narrators</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Confirms the names of Hadith books</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Ascertain the number of ahadith</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Explain the contents of the sunnah</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Asmau al-rijal means, \"names of men (reporters of Hadith) was introduce to authenticate chains of hadith narators. </div>", "topic": "HADITH : AUTHENTICATION OF HADITH"}, {"id": "objective>IRK>2008>12", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The real name of Imam al-Bukhari is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Musa b. Muhammad</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Muhammad b. Ahmad</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Isma'il b. Yaqub</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Muhammad b. Isma'il</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Option D  <br/> The full name of Imam Bukhari was Muhammed bin Ismail bin Ibrahim. He was born in Bukhara village </div>", "topic": "HADITH : HISTORY OF HADITH LITERATURE -COLLECTION OF HADITH FROM THE TIME OF THE PROPHET-SAW TO THE PERIOD OF THE SIX AUTHENTIC COLLECTORS OF HADITH"}, {"id": "objective>IRK>2008>13", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A Hadith in which the chain of narration and text are sound is known as</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Mash'hur</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Maqtu'</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Mursal</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Sahih</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">A Hadith in which the chain of narration and text are sound is known as Sahih. Sahih Hadiths are considered the most authentic and reliable Hadiths in Islamic tradition. They are characterized by a continuous and reliable chain of narrators, the integrity and strong memory of the narrators, and the Hadith text does not contradict the Quran or other Sahih Hadiths.</div>", "topic": "HADITH : AUTHENTICATION OF HADITH"}, {"id": "objective>IRK>2008>14", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following directly applies to Hadith ad-Da'if?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">It can be used on certain conditions</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Its rejection is due to its weakness all the times</div>", "<div style=\"font-family:Cambria;font-size:17px;\">It can be equated with al- Mauduf</div>", "<div style=\"font-family:Cambria;font-size:17px;\">It's legal status cannot be ascertained</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Hadith Daif means weak which can be used on certain conditions. The weakness of Hadith could be through chains of transmittors, poor memory of the reporters and questionable character of the reporter </div>", "topic": "HADITH : AUTHENTICATION OF HADITH"}, {"id": "objective>IRK>2008>15", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The Glorious Qur'an takes precedence over the Hadith in that</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">it can be used for prayers</div>", "<div style=\"font-family:Cambria;font-size:17px;\">the former is recited in prayers</div>", "<div style=\"font-family:Cambria;font-size:17px;\">the latter can be invoked against evil</div>", "<div style=\"font-family:Cambria;font-size:17px;\">only the former is used in judicial matters</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Quaran can be recited during prayers while hadith can not be recited during prayers </div>", "topic": "HADITH : THE RELATIONSHIP BETWEEN HADITH AND THE GLORIOUS QUR’AN"}, {"id": "objective>IRK>2008>16", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Hadith is important to Muslims because it is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">miracle of Islam</div>", "<div style=\"font-family:Cambria;font-size:17px;\">the most reliable sayings of the prophet (SAW)</div>", "<div style=\"font-family:Cambria;font-size:17px;\">the only linkage between the prophet(SAW) and the Muslim</div>", "<div style=\"font-family:Cambria;font-size:17px;\">the means through which the prophet's message is known</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Hadith is important to Muslims because it is the means through which the prophet's message is known. Hadiths provide context to the verses of the Qur'an and offer guidance on how to live according to Islamic principles. They are a crucial source of Islamic law and belief, supplementing the Qur'an by providing detailed accounts of the Prophet's life, his sayings, actions, and tacit approvals.</div>", "topic": "HADITH : AUTHENTICATION OF HADITH"}, {"id": "objective>IRK>2008>17", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following is the correct order of authenticity of three of the six sound collections of the Hadith</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Bukhari, Muslim and Tirmidhi</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Ibn Majah, Muslim and Nasa'i</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Muslim, Nasa'i and Ibn Majah</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Abu Dawud, Tirmidhi and Bukhari</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The Hadiths are collections of the sayings, actions, and approvals of the Prophet Muhammad. They are ranked in terms of authenticity. The most authentic collections are Sahih Bukhari and Sahih Muslim. These are followed by the collections of Tirmidhi, Abu Dawud, Nasa'i, and Ibn Majah. Therefore, the correct order of authenticity is Bukhari, Muslim, and Tirmidhi.</div>", "topic": "HADITH : THE SIX SOUND COLLECTORS OF HADITH – BIOGRAPHIES AND THEIR WORKS."}, {"id": "objective>IRK>2008>18", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The first major written work of a hadith was</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Sahih Muslim</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Sunan Ibn Majah</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Muwata Malik</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Musnad Ahmad</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The first major written work of a hadith was Muwatta Malik. It was compiled by Imam Malik ibn Anas and is considered to be from the earliest written collections of hadith literature in the history of Islam.</div>", "topic": "HADITH : HISTORY OF HADITH LITERATURE -COLLECTION OF HADITH FROM THE TIME OF THE PROPHET-SAW TO THE PERIOD OF THE SIX AUTHENTIC COLLECTORS OF HADITH"}, {"id": "objective>IRK>2008>19", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The collection of Imam Muslim differs from that of Imam Bukhari in terms of</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Interpretation</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Authenticity</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Repetition</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Clasification</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The collection of Imam Muslim differs from that of Imam Bukhari in terms of clasification.</div>", "topic": "HADITH : THE SIX SOUND COLLECTORS OF HADITH – BIOGRAPHIES AND THEIR WORKS."}, {"id": "objective>IRK>2008>20", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Hadith 11 of an-Nawawi admonishes Muslims to</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">be certain in some acts of worship</div>", "<div style=\"font-family:Cambria;font-size:17px;\">avoid doubtful things</div>", "<div style=\"font-family:Cambria;font-size:17px;\">note that doubt and uncertainty are close to each other</div>", "<div style=\"font-family:Cambria;font-size:17px;\">always do things clearly</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Hadith 11 of an-Nawawi admonishes Muslims to avoid doubtful things. This Hadith is often quoted as 'Leave that which makes you doubt for that which does not make you doubt.' The purpose of this Hadith is to guide Muslims to clear and certain actions in their faith and life, and to avoid doubtful matters that could lead to wrongdoing or sin.</div>", "topic": "HADITH : THE STUDY OF THE ARABIC TEXTS OF THE FOLLOWING AHADITH FROMAN-NAWAWI’S COLLECTION: 1,3,5,6,7,9,10,11,12,13,15,16, 18,19,21,22,25,27,34, AND 41"}, {"id": "objective>IRK>2008>21", "question": "<div style=\"font-family:Cambria;font-size:17px;\">According to Hadith 41 of an- Nawawi, the faith of a believer is incomplete until he</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Loves for his brother what he love himself</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Hate all kinds of evil</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Likes good things for his family</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Follows what has been revealed unto the prophet(SAW)</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Option D <br/> \"None of you is a believer until his desire follow that which I brought </div>", "topic": "MORAL LESSONS IN THE GLORIOUS QUR'AN AND HADITH : BEHAVIOUR AND MODESTY IN DRESSING"}, {"id": "objective>IRK>2008>22", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The message in Hadith 34 of an- Nawawi is about</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Performing the society for the better</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Preventing evil in the society by any means possible</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Commanding good among people</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Abstaining from evil deeds</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">\"... Any one amongst you who sees abomination act should change it with his hand. If he is not capable, then he should use his tongue, if he is not capable, then he should use his heart through it is the weakest level of faith. </div>", "topic": "MORAL LESSONS IN THE GLORIOUS QUR'AN AND HADITH : ENJOINING WHAT IS GOOD AND FORBIDDING WHAT IS WRONG HADITH 25 AND 34 OF AN NAWAWI"}, {"id": "objective>IRK>2008>23", "question": "<div style=\"font-family:Cambria;font-size:17px;\"><img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/> The Hadith above warns Muslims against charity with</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">useless things</div>", "<div style=\"font-family:Cambria;font-size:17px;\">ill-gotten wealth</div>", "<div style=\"font-family:Cambria;font-size:17px;\">evil intention</div>", "<div style=\"font-family:Cambria;font-size:17px;\">cheap things</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">\"Allah, the all mighty is good and accept only what is good\" </div>", "topic": "HADITH : THE STUDY OF THE ARABIC TEXTS OF THE FOLLOWING AHADITH FROMAN-NAWAWI’S COLLECTION: 1,3,5,6,7,9,10,11,12,13,15,16, 18,19,21,22,25,27,34, AND 41"}, {"id": "objective>IRK>2008>24", "question": "<div style=\"font-family:Cambria;font-size:17px;\"><img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/> The verse above teaches that Muslims should</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Travel round the world and see wonders</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Explore the earth and be learned</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Go into the earth and see Allah's creatures</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Disperse into the land and earn a living</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">\"... you may disperse through land and seek for the bounty of Allah (by working) etc Suratu Jamiah  <br/> (Q62:10 </div>", "topic": "IMPORTANCE OF THE GLORIOUS QUR’AN : AS SOURCE OF GUIDANCE IN SPIRITUAL, MORAL, ECONOMIC, POLITICAL AND SOCIO-CULTURAL MATTERS."}, {"id": "objective>IRK>2008>25", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Good behavior and modesty in dress in Islam is an essential parts of</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Amal</div>", "<div style=\"font-family:Cambria;font-size:17px;\">duty</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Iman</div>", "<div style=\"font-family:Cambria;font-size:17px;\">beauty</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Good behaviour (Amalu Salih) and modesty in dress (Al-Hayah) are part of Imam(faith)</div>", "topic": "MORAL LESSONS IN THE GLORIOUS QUR'AN AND HADITH : BEHAVIOUR AND MODESTY IN DRESSING"}, {"id": "objective>IRK>2008>26", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Hadith 18 of an-Nwawai enjoins believers to</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Be firm abravend</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Be strong-minded and clean</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Have piety and work righteously</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Acquire knowledge and be polite</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Hadith 18 of an-Nawawi enjoins believers to 'Have piety and work righteously'. This Hadith emphasizes the importance of having fear and respect for Allah (piety) and doing good deeds (working righteously).</div>", "topic": "MORAL LESSONS IN THE GLORIOUS QUR'AN AND HADITH : PIETY-TAQWA HADITH 18 AND 35 OF AN NAWAWI"}, {"id": "objective>IRK>2008>27", "question": "<div style=\"font-family:Cambria;font-size:17px;\"><img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/> The verse above urges</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Mankind to be patient and persevere</div>", "<div style=\"font-family:Cambria;font-size:17px;\">The Makkans to persevere and be patient</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Anyone in hardship to persevere and be patient</div>", "<div style=\"font-family:Cambria;font-size:17px;\">The believers to be patient and persevere</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">\"O you who believe, endure, and be more patient. - Q3:200</div>", "topic": "MORAL LESSONS IN THE GLORIOUS QUR'AN AND HADITH : TOLERANCE, PERSEVERANCE AND PATIENCE HADITH 16 OF AN-NAWAWI"}, {"id": "objective>IRK>2008>28", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Q. 3:103 enjoins Muslims to</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Unite and not be divided</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Live in the same place</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Speak with one voice politically</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Unite for economic progress</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Q3:103  <br/> \"And hold fast all of you together to the rope of Allah (Quran) and not to be divided among yourselves. </div>", "topic": "MORAL LESSONS IN THE GLORIOUS QUR'AN AND HADITH : UNITY AND BROTHERHOOD HADITH 35 OF AN-NAWAWI"}, {"id": "objective>IRK>2008>29", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Prophet Muhammad (SAW) was described as the seal of all prophets, meaning that he</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Was the last or the prophets of Allah</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Covered all parts of the world preaching</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Is reserved even by the Jews</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Was accepted by all Christian</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Muhammed(SAW) is the father of any of you men, but he is the messager of Allah and the (last) end of the prophets - Q33:40 </div>", "topic": "THE LIFE OF PROPHET MUHAMMAD (SAW) : HIS CALL TO PROPHETHOOD"}, {"id": "objective>IRK>2008>30", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The act of taking refuge from the Jinns as mentioned in Q. 72:6 is that</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">They could harm the believers</div>", "<div style=\"font-family:Cambria;font-size:17px;\">People benefit from their protection</div>", "<div style=\"font-family:Cambria;font-size:17px;\">They would increase such people in fury</div>", "<div style=\"font-family:Cambria;font-size:17px;\">people may turn to be their partners</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">\"And verily, there were men among mankind who took shelter with the males among jinn, but the Jinn increase them in sin and transgression </div>", "topic": "ARTICLE OF FAITH : BELIEF IN ALLAH'S ANGELS"}, {"id": "objective>IRK>2008>31", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The attributes of Allah as contained in Q. 59:23 are</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">5</div>", "<div style=\"font-family:Cambria;font-size:17px;\">6</div>", "<div style=\"font-family:Cambria;font-size:17px;\">7</div>", "<div style=\"font-family:Cambria;font-size:17px;\">8</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Option D <br/> Q59:23  <br/> \"he is Allah beside whom Lailaha illa Huwa (none has the right to be worshipped but he), the king, the holy, the free from all defect, the giver of security, the watcher over his creatures, the all mighty, the compeller, the supreme glory be to Allah(High is he) above all that they associate as partners with him </div>", "topic": "ARTICLE OF FAITH : BELIEF IN ALLAH"}, {"id": "objective>IRK>2008>32", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The important of Salah as listed in Q. 29:45 includes</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Prohibition of shameful and deeds</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Making invocations regularly</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Prohibition of cheating in measures</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Prohibition of hoarding</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">\"...Verily, As-salat (the prayer) prevents from Al-fahsha' (great sins of every kind, unlawful sexual intercourse) and Al-mun kar (disbelieve, polytheism and every kind of evil wicked deed)... Q29:45 </div>", "topic": "IBADAT AND THEIR TYPES : SALAH"}, {"id": "objective>IRK>2008>33", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following vitiates Salah?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Intoxication</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Adornment</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Falsehood</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Yawning</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Intoxication vitiates Salah because it impairs a person's ability to concentrate and understand what they are saying or doing during the prayer. Therefore, the correct answer is 'Intoxication'.</div>", "topic": "IBADAT AND THEIR TYPES : SALAH"}, {"id": "objective>IRK>2008>34", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A major activity in Salah performed through various bodily postures is known as</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Raka'at</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Takbiratul Ihram</div>", "<div style=\"font-family:Cambria;font-size:17px;\">At- tashahud</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Sujud ash-shukr</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Raka'at refers to the various bodily postures and movements performed in Salah, including standing, bowing, prostrating, and sitting. Therefore, the correct answer is 'Raka'at'.</div>", "topic": "IBADAT AND THEIR TYPES : SALAH"}, {"id": "objective>IRK>2008>35", "question": "<div style=\"font-family:Cambria;font-size:17px;\">In congregational Salah, a person who comes late is expected to</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">pronounce the taslim to indicate his arrival</div>", "<div style=\"font-family:Cambria;font-size:17px;\">say subhanallah so that the Imam can note his presence</div>", "<div style=\"font-family:Cambria;font-size:17px;\">recite the iqama before joining the congregation</div>", "<div style=\"font-family:Cambria;font-size:17px;\">make takbiratul ihram and join the Imam</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">In congregational Salah, a person who comes late is expected to make takbiratul ihram and join the Imam. Takbiratul Ihram is the first 'Allahu Akbar' that initiates the prayer. It is a requirement for the person to do this before joining the prayer.</div>", "topic": "IBADAT AND THEIR TYPES : SALAH"}, {"id": "objective>IRK>2008>36", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Hajj is one of the avenues for Islamic brotherhood and</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">kindness</div>", "<div style=\"font-family:Cambria;font-size:17px;\">fairness</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Trust</div>", "<div style=\"font-family:Cambria;font-size:17px;\">unity</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Hajj is one of the avenues for Islamic brotherhood and unity. The Hajj pilgrimage is a symbol of unity among Muslims, as it brings together believers from all walks of life and from every corner of the globe.</div>", "topic": "IBADAT AND THEIR TYPES : HAJJ"}, {"id": "objective>IRK>2008>37", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The type of Zakah due at the end of Ramadan fast is known as</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Zakah al-mal</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Zakah al-fitr</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Zakah al-anam</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Zakah al-harth</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The type of Zakah due at the end of Ramadan fast is known as Zakah al-fitr. Zakah al-Fitr is a form of charity given to the poor at the end of the fasting in the Islamic holy month of Ramadan.</div>", "topic": "IBADAT AND THEIR TYPES : ZAKAH"}, {"id": "objective>IRK>2008>38", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The gathering of pilgrims on the 9th day of Dhul Hijjah is known as</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Wuquf bi 'Arefah</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Sajadah 'Arefah</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Jabal 'Arefah</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Da'al al-'Arefah</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Muslim pilgrims gathered on the 9th of D hul Hijah at the plane ground of Arafah. It is called Wuquf bil Arafah </div>", "topic": "IBADAT AND THEIR TYPES : HAJJ"}, {"id": "objective>IRK>2008>39", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The categories of women prohibited in marriage due to blood relations are</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">14</div>", "<div style=\"font-family:Cambria;font-size:17px;\">11</div>", "<div style=\"font-family:Cambria;font-size:17px;\">10</div>", "<div style=\"font-family:Cambria;font-size:17px;\">7</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">There are seven (7) categories of women prohibited in marriage due to blood relations according to Qur'an 4:23: <br/>  <br/> Mother <br/>  <br/> Daughter <br/>  <br/> Sister <br/>  <br/> Paternal aunt (father's sister) <br/>  <br/> Maternal aunt (mother's sister) <br/>  <br/> Brother's daughter (niece) <br/>  <br/> Sister's daughter (niece)</div>", "topic": "FAMILY MATTERS : MARRIAGE"}, {"id": "objective>IRK>2008>40", "question": "<div style=\"font-family:Cambria;font-size:17px;\">According to Q.4:34, the main right of the husband over his wife is to</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Prepare food for him</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Have conjugal relation with her</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Accept his leadership and obey him</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Appreciate him for his favours</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">\"Men are protectors and maintainers of women, because Allah has made one of them to excel the other and because they spend --- Q4:34 </div>", "topic": "FAMILY MATTERS : MARRIAGE"}, {"id": "objective>IRK>2008>41", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A marriage is not valid in Islam without</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">At least two witnesses</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Slaughtering an animal</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Marriage garment</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Deciding the place of residence</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">In Islam, a marriage is not valid without at least two witnesses. This is to ensure the legality and transparency of the marriage contract. The presence of witnesses helps to prevent disputes and misunderstandings in the future.</div>", "topic": "FAMILY MATTERS : MARRIAGE"}, {"id": "objective>IRK>2008>42", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The right of a husband over his wife excludes</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Controlling the wife's activities</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Taking additional wives</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Deciding the place of residence</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Total controlling the wife's property</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The right of a husband over his wife excludes total controlling the wife's property. In Islam, a woman has the right to own, manage, and dispose of her property without interference from her husband or anyone else.</div>", "topic": "FAMILY MATTERS : MARRIAGE"}, {"id": "objective>IRK>2008>43", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Talaq al bai'in technically conveys the idea of</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Divorce of a new bride</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Court annulment of marriage</div>", "<div style=\"font-family:Cambria;font-size:17px;\">An irrevocable divorce</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Divorce in a state of impurity</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Talaq al bai'in technically conveys the idea of an irrevocable divorce. This is a type of divorce in Islam where the husband has no right to take back his wife unless a new marriage contract is agreed upon.</div>", "topic": "FAMILY MATTERS : DIVORCE"}, {"id": "objective>IRK>2008>44", "question": "<div style=\"font-family:Cambria;font-size:17px;\">When a woman is observing iddah aiwafat, she is permitted to</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Wear jewellery of any kind</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Use any type of perfume</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Cut her finger nails</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Beautify herself</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Cutting of finger nails is not part of what a woman observing Idolat-ul wafat should not do </div>", "topic": "FAMILY MATTERS : IDRAR: ILL-TREATMENT OF WIFE"}, {"id": "objective>IRK>2008>45", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Zihar occurs when a husband compares his</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Wife with himself</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Wife with his daughter</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Daughter with her friend</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Wife with the back of his mother</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Zihar is a pre-Islamic Arabian form of divorce where a man says to his wife 'you are to me as the back of my mother'. This is considered a form of divorce in Islam.</div>", "topic": "FAMILY MATTERS : DIVORCE"}, {"id": "objective>IRK>2008>46", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Excluded from inheritance is a</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Brother from the estate of his deceased brother</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Man after the death of his wife</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Person who kills his father for his estate</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Woman because of her gender</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">In Islamic law, a person who kills another is excluded from inheriting from the deceased. This is based on the principle that a person should not benefit from his or her wrongdoing.</div>", "topic": "FAMILY MATTERS : INHERITANCE"}, {"id": "objective>IRK>2008>47", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Qlyas in Islamic law refers to</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Measurement</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Analogical deduction</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Intelligent work</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Evaluation</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Qiyas is an Islamic legal term that refers to analogical deduction. It is one of the four sources of Islamic law, the others being the Quran, Sunnah, and Ijma (consensus).</div>", "topic": "SOURCES AND SCHOOLS OF LAW : THE FOUR MAJOR SOURCES THE QUR'AN, SUNNAH, IJMA AND QIYAS"}, {"id": "objective>IRK>2008>48", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Raiding as a characteristic of the Jahilyyah Arabs led to</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Holding annual political meetings</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Staging of annual trade fair</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Burying their female children alive</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Fighting inter- tribal wars</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Raiding was a common practice among the Jahiliyyah Arabs, which often led to inter-tribal wars. Jahiliyyah refers to the period of ignorance before the advent of Islam.</div>", "topic": "ISLAMIC HISTORY AND CIVILIZATION - PRE-ISLAMIC ARABIA JAHILIYYAH : JAHILIYYAH PRACTICES: IDOL WORSHIP, INFANTICIDE, POLYANDRY, GAMBLING, USURY, ETC."}, {"id": "objective>IRK>2008>49", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The caliph who introduced stipend for teachers was</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Abu Bakr</div>", "<div style=\"font-family:Cambria;font-size:17px;\">'Umar</div>", "<div style=\"font-family:Cambria;font-size:17px;\">'Uthman</div>", "<div style=\"font-family:Cambria;font-size:17px;\">'Ali</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Caliph Umar bin At-khatab introduced stipend for teachers and armies to encourage learning and security. </div>", "topic": "THE LIFE OF PROPHET MUHAMMAD (SAW) : ADMINISTRATION OF THE UMMAH AND THE ROLE OF THE MOSQUE (Q.3:159) (Q.4:58 AND 135)"}, {"id": "objective>IRK>2008>50", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The main impact of Islamic values on social life of the people of West Africa is the</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Performance of Salah by Muslims</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Modification of polygamy in line with Islamic principles</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Adoption of Arabic words in many languages</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Avoidance of alcoholic drink in public places</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">There are several Arabic words adopted by many languages in west Africa. </div>", "topic": "THE IMPACT OF ISLAM IN WEST AFRICA : THE INFLUENCE OF ISLAM ON THE SOCIO-POLITICAL LIFE OF SOME WEST AFRICAN EMPIRES: GHANA, MALI, SONGHAI AND BORNO"}];
